207	inline NGP_HOST_DEVICE uint32_t binary_search(float val, const float* data, uint32_t length) {
208		if (length == 0) {
209			return 0;
210		}
211	
212		uint32_t it;
213		uint32_t count, step;
214		count = length;
215	
216		uint32_t first = 0;
217		while (count > 0) {
218			it = first;
219			step = count / 2;
220			it += step;
221			if (data[it] < val) {
222				first = ++it;
223				count -= step + 1;
224			} else {
225				count = step;
226			}
227		}
228	
229		return min(first, length - 1);
230	}
