237		NGP_HOST_DEVICE T at(const ivec2& px) const { return data[px.x + px.y * resolution.x]; }
238	
239		// Lookup via UV coordinates in [0,1]^2
240		NGP_HOST_DEVICE T at(const vec2& uv) const {
241			ivec2 px = clamp(ivec2(vec2(resolution) * uv), 0, resolution - 1);
242			return at(px);
243		}
244	
245		// Lookup via UV coordinates in [0,1]^2 and LERP the nearest texels
246		NGP_HOST_DEVICE T at_lerp(const vec2& uv) const {
247			const vec2 px_float = vec2(resolution) * uv;
248			const ivec2 px = ivec2(px_float);
249	
250			const vec2 weight = px_float - vec2(px);
251	
252			auto read_val = [&](ivec2 pos) { return at(clamp(pos, 0, resolution - 1)); };
253	
254			return (
255				(1 - weight.x) * (1 - weight.y) * read_val({px.x, px.y}) + (weight.x) * (1 - weight.y) * read_val({px.x + 1, px.y}) +
256				(1 - weight.x) * (weight.y) * read_val({px.x, px.y + 1}) + (weight.x) * (weight.y) * read_val({px.x + 1, px.y + 1})
257			);
258		}
259	
260		NGP_HOST_DEVICE operator bool() const { return data; }
261	};
